class SignedMessageInspector {

    public SignedMessageDetails inspectAndVerify(SOAPMessage soapMessage) throws Exception {
        Document document = toDocument(soapMessage);
        SignedMessageDetails details = new SignedMessageDetails();

        NodeList signatureNodes = document.getElementsByTagNameNS(XMLSignature.XMLNS, "Signature");
        if (signatureNodes == null || signatureNodes.getLength() == 0) {
            throw SoapFaults.securityFault("No XML Signature found in SOAP message");
        }

        Element signatureElement = (Element) signatureNodes.item(0);
        X509Certificate certificate = extractCertificate(document);
        if (certificate == null) {
            throw SoapFaults.securityFault("No X509 certificate found in WS-Security header");
        }

        XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
        DOMValidateContext validateContext = new DOMValidateContext(certificate.getPublicKey(), signatureElement);
        markIdAttributes(document.getDocumentElement());
        XMLSignature signature = factory.unmarshalXMLSignature(validateContext);
        boolean valid = signature.validate(validateContext);

        details.setSignatureValid(valid);
        details.setSignerSubject(certificate.getSubjectX500Principal().getName());
        details.setSignedElementNames(extractSignedElements(signature, document));

        return details;
    }

    private Document toDocument(SOAPMessage soapMessage) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        soapMessage.writeTo(baos);
        byte[] bytes = baos.toByteArray();

        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        return dbf.newDocumentBuilder().parse(new InputSource(new ByteArrayInputStream(bytes)));
    }

    private X509Certificate extractCertificate(Document document) throws Exception {
        NodeList bstNodes = document.getElementsByTagNameNS(
                "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd",
                "BinarySecurityToken");
        if (bstNodes == null || bstNodes.getLength() == 0) {
            return null;
        }

        String base64 = bstNodes.item(0).getTextContent().replaceAll("\\s+", "");
        byte[] certBytes = java.util.Base64.getDecoder().decode(base64);
        java.security.cert.CertificateFactory cf = java.security.cert.CertificateFactory.getInstance("X.509");
        return (X509Certificate) cf.generateCertificate(new ByteArrayInputStream(certBytes));
    }

    private void markIdAttributes(Element element) {
        if (element == null) {
            return;
        }
        if (element.hasAttribute("Id")) {
            element.setIdAttribute("Id", true);
        }
        if (element.hasAttributeNS(WSConstants.WSU_NS, "Id")) {
            element.setIdAttributeNS(WSConstants.WSU_NS, "Id", true);
        }
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node n = children.item(i);
            if (n instanceof Element) {
                markIdAttributes((Element) n);
            }
        }
    }

    private List<String> extractSignedElements(XMLSignature signature, Document document) {
        SignedInfo signedInfo = signature.getSignedInfo();
        List<String> names = new ArrayList<>();
        for (Object obj : signedInfo.getReferences()) {
            Reference ref = (Reference) obj;
            String uri = ref.getURI();
            if (uri != null && uri.startsWith("#")) {
                String id = uri.substring(1);
                Element target = findById(document.getDocumentElement(), id);
                if (target != null) {
                    names.add(target.getLocalName() != null ? target.getLocalName() : target.getNodeName());
                } else {
                    names.add(id);
                }
            }
        }
        return names;
    }

    private Element findById(Element element, String id) {
        if (element == null) {
            return null;
        }
        if (id.equals(element.getAttribute("Id")) || id.equals(element.getAttributeNS(WSConstants.WSU_NS, "Id"))) {
            return element;
        }
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node n = children.item(i);
            if (n instanceof Element) {
                Element found = findById((Element) n, id);
                if (found != null) {
                    return found;
                }
            }
        }
        return null;
    }
}

