class SoapFaults {

    static SOAPFaultException clientFault(String message) {
        return fault("Client", message);
    }

    static SOAPFaultException serverFault(String message) {
        return fault("Server", message);
    }

    static SOAPFaultException securityFault(String message) {
        return fault("Sender", "WS-Security Error: " + message);
    }

    private static SOAPFaultException fault(String code, String message) {
        try {
            SOAPFactory factory = SOAPFactory.newInstance(SOAPConstants.SOAP_1_2_PROTOCOL);
            SOAPFault fault = factory.createFault();
            fault.setFaultString(message);
            fault.setFaultCode(new QName("http://www.w3.org/2003/05/soap-envelope", code));
            return new SOAPFaultException(fault);
        } catch (SOAPException e) {
            throw new RuntimeException(message, e);
        }
    }
}

class BankingSecurityCallbackHandler implements javax.security.auth.callback.CallbackHandler {

    private final String keystorePath;
    private final String keystorePassword;
    private final String keyPassword;

    BankingSecurityCallbackHandler(String keystorePath, String keystorePassword, String keyPassword) {
        this.keystorePath = keystorePath;
        this.keystorePassword = keystorePassword;
        this.keyPassword = keyPassword;
    }

    @Override
    public void handle(javax.security.auth.callback.Callback[] callbacks) {
        for (javax.security.auth.callback.Callback callback : callbacks) {
            if (callback instanceof org.apache.wss4j.common.ext.WSPasswordCallback) {
                org.apache.wss4j.common.ext.WSPasswordCallback pc =
                        (org.apache.wss4j.common.ext.WSPasswordCallback) callback;
                pc.setPassword(keyPassword);
            }
        }
    }
}

class SignedElementsCaptureInterceptor extends AbstractPhaseInterceptor<Message> {

    SignedElementsCaptureInterceptor() {
        super(Phase.PRE_INVOKE);
    }

    @Override
    public void handleMessage(Message message) {
        @SuppressWarnings("unchecked")
        List<WSSecurityEngineResult> results =
                (List<WSSecurityEngineResult>) message.get(org.apache.cxf.ws.security.SecurityConstants.RECV_RESULTS);
        if (results == null) {
            return;
        }

        List<String> signedElements = new ArrayList<>();
        String signer = null;

        for (WSSecurityEngineResult result : results) {
            Integer action = (Integer) result.get(WSSecurityEngineResult.TAG_ACTION);
            if (action != null && (action == WSConstants.SIGN || action == WSConstants.ST_SIGNED)) {
                @SuppressWarnings("unchecked")
                List<WSDataRef> refs = (List<WSDataRef>) result.get(WSSecurityEngineResult.TAG_DATA_REF_URIS);
                if (refs != null) {
                    for (WSDataRef ref : refs) {
                        QName qName = ref.getName();
                        if (qName != null) {
                            signedElements.add(qName.toString());
                        }
                    }
                }
                X509Certificate cert = (X509Certificate) result.get(WSSecurityEngineResult.TAG_X509_CERTIFICATE);
                if (cert != null) {
                    signer = cert.getSubjectX500Principal().getName();
                }
            }
        }

        message.put("banking.signed.elements", signedElements);
        message.put("banking.signer.subject", signer);
    }
}

class BankingServicePublisher {

    public static void main(String[] args) {
        String address = "http://0.0.0.0:8080/services/banking";

        JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
        factory.setServiceClass(BankingTransactionPortType.class);
        factory.setServiceBean(new BankingTransactionService());
        factory.setAddress(address);

        factory.getInInterceptors().add(new LoggingInInterceptor());
        factory.getInInterceptors().add(new SAAJInInterceptor());
        factory.getInInterceptors().add(buildWss4jInInterceptor());
        factory.getInInterceptors().add(new SignedElementsCaptureInterceptor());

        Server server = factory.create();
        System.out.println("Banking SOAP service started at " + address);
    }

    private static WSS4JInInterceptor buildWss4jInInterceptor() {
        java.util.Map<String, Object> props = new java.util.HashMap<>();
        props.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        props.put(WSHandlerConstants.SIG_PROP_FILE, "banking-verification.properties");
        props.put(WSHandlerConstants.SIG_VER_PROP_FILE, "banking-verification.properties");
        props.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        props.put(WSHandlerConstants.MUST_UNDERSTAND, "false");
        return new WSS4JInInterceptor(props);
    }
}

class BankingClientExample {

    public static void main(String[] args) throws Exception {
        QName serviceName = new QName("http://enterprise.com/banking/api", "BankingTransactionService");
        QName portName = new QName("http://enterprise.com/banking/api", "BankingTransactionPort");

        java.net.URL wsdl = new java.net.URL("http://localhost:8080/services/banking?wsdl");
        Service service = Service.create(wsdl, serviceName);
        BankingTransactionPortType port = service.getPort(portName, BankingTransactionPortType.class);

        BindingProvider bp = (BindingProvider) port;
        Map<String, Object> ctx = bp.getRequestContext();
        ctx.put(SecurityConstants.CALLBACK_HANDLER,
                new BankingSecurityCallbackHandler("client-keystore.jks", "changeit", "changeit"));
        ctx.put(SecurityConstants.SIGNATURE_PROPERTIES, "banking-signature.properties");
        ctx.put(SecurityConstants.SIGNATURE_USERNAME, "banking-client");
        ctx.put(SecurityConstants.SIGNATURE_CRYPTO, createCrypto("client-keystore.jks", "changeit"));
        ctx.put(SecurityConstants.SIGNATURE_ALGORITHM, SignatureMethod.RSA_SHA256);
        ctx.put(SecurityConstants.ENABLE_STREAMING_SECURITY, false);

        org.apache.cxf.endpoint.Client client = org.apache.cxf.frontend.ClientProxy.getClient(port);
        java.util.Map<String, Object> outProps = new java.util.HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, "banking-client");
        outProps.put(WSHandlerConstants.PW_CALLBACK_REF,
                new BankingSecurityCallbackHandler("client-keystore.jks", "changeit", "changeit"));
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "banking-signature.properties");
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
                "{Element}{http://www.w3.org/2003/05/soap-envelope}Body;"
                        + "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp");
        client.getOutInterceptors().add(new org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor(outProps));

        TransactionRequest request = new TransactionRequest();
        request.setAccountFrom("10000001");
        request.setAccountTo("20000002");
        request.setAmount(new BigDecimal("1500.00"));
        request.setCurrency("USD");
        request.setTransactionType("TRANSFER");
        request.setReference("INV-2026-001");

        TransactionResponse response = port.processTransaction(request);
        System.out.println(response.getTransactionId());
        System.out.println(response.getStatus());
        System.out.println(response.getMessage());
        System.out.println(response.getSignedElements());
        System.out.println(response.getSignerSubject());
    }

    private static Crypto createCrypto(String keystorePath, String password) throws WSSecurityException {
        java.util.Properties props = new java.util.Properties();
        props.put("org.apache.wss4j.crypto.provider", "org.apache.wss4j.common.crypto.Merlin");
        props.put("org.apache.wss4j.crypto.merlin.keystore.type", "jks");
        props.put("org.apache.wss4j.crypto.merlin.keystore.password", password);
        props.put("org.apache.wss4j.crypto.merlin.keystore.file", keystorePath);
        return new Merlin(props, BankingClientExample.class.getClassLoader(), null);
    }
}